    fn tokenToSymbol(self: *BaseParser, token: Token) u16 {
        return switch (token.cat) {
            .@"eof" => 1,
            .@"ident" => self.identToSymbol(token),
            .@"newline" => 66,
            .@"drop_stmt" => 71,
            .@"string_sq" => 76,
            .@"string_dq" => 77,
            .@"indent" => 82,
            .@"outdent" => 83,
            .@"kwarg_name" => 93,
            .@"suffix_q" => 102,
            .@"suffix_bang" => 103,
            .@"read_pfx" => 104,
            .@"write_pfx" => 105,
            .@"integer" => 108,
            .@"bar_capture" => 114,
            .@"share_pfx" => 119,
            .@"ternary_if" => 127,
            .@"post_if" => 130,
            .@"minus_prefix" => 141,
            .@"move_pfx" => 144,
            .@"clone_pfx" => 145,
            .@"pin_pfx" => 146,
            .@"raw_pfx" => 147,
            .@"real" => 153,
            .@"true" => 154,
            .@"false" => 155,
            .@"dot_lit" => 159,
            .@"dot_lbrace" => 161,
            .@"colon" => 67,
            .@"assign" => 69,
            .@"lparen" => 96,
            .@"comma" => 97,
            .@"rparen" => 100,
            .@"lbracket" => 106,
            .@"rbracket" => 107,
            .@"dot" => 122,
            .@"ampersand" => 142,
            .@"tilde" => 143,
            .@"star" => 148,
            .@"at" => 160,
            .@"rbrace" => 164,
            .@"lbrace" => 165,
            .@"bar" => 187,
