            .@"fixed_assign" => 70,
            .@"arrow" => 101,
            .@"dotdot" => 123,
            .@"fat_arrow" => 124,
            .@"nullish" => 128,
            .@"plus_assign" => 136,
            .@"minus_assign" => 137,
            .@"star_assign" => 138,
            .@"slash_assign" => 139,
            .@"move_assign" => 140,
            .@"pipe" => 184,
            .@"or_sym" => 185,
            .@"and_sym" => 186,
            .@"eq" => 189,
